import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../../config/design_tokens.dart';import '../../../features/parking/data/providers.dart';import '../../../features/search/presentation/search_controller.dart';
class FreiraumMap extends ConsumerWidget{const FreiraumMap({super.key});@override Widget build(BuildContext context,WidgetRef ref){final spaces=ref.watch(parkingResultsProvider);final selected=ref.watch(selectedParkingIdProvider);final q=ref.watch(searchProvider);return Semantics(label:'Interaktive Demo-Karte Frankfurt mit ungefähren Stellplatzpositionen',child:Stack(children:[CustomPaint(size:Size.infinite,painter:_Grid()),...spaces.asMap().entries.map((e){final s=e.value;final x=(.15+(s.lng-8.63)*7).clamp(.08,.9).toDouble();final y=(.75-(s.lat-50.09)*8).clamp(.12,.78).toDouble();final sel=s.id==selected;return AnimatedPositioned(duration:T.normal,left:MediaQuery.sizeOf(context).width*x,top:MediaQuery.sizeOf(context).height*y,child:Semantics(button:true,label:'Marker ${s.title}',child:GestureDetector(onTap:()=>ref.read(selectedParkingIdProvider.notifier).state=s.id,child:AnimatedScale(scale:sel?1.18:1,duration:T.fast,child:Container(padding:const EdgeInsets.symmetric(horizontal:10,vertical:7),decoration:BoxDecoration(color:sel?T.ink:T.surface,borderRadius:BorderRadius.circular(999),boxShadow:T.shadow,border:Border.all(color:T.mint,width:2)),child:Text('${s.hourlyPrice.toStringAsFixed(0)}€',style:TextStyle(color:sel?Colors.white:T.ink,fontWeight:FontWeight.w900)))))));}),if(q.destination!=null) Positioned(left:MediaQuery.sizeOf(context).width*.48,top:MediaQuery.sizeOf(context).height*.36,child:const Icon(Icons.flag_circle,color:T.amber,size:38)),const Positioned(right:12,bottom:82,child:Text('© OpenStreetMap · Demo-Daten',style:TextStyle(fontSize:11,color:T.muted))) ]));}}
class _Grid extends CustomPainter{@override void paint(Canvas c,Size s){c.drawRect(Offset.zero&s,Paint()..color=T.porcelain);final p=Paint()..color=T.line..strokeWidth=1;for(double x=-60;x<s.width;x+=54)c.drawLine(Offset(x,0),Offset(x+260,s.height),p);for(double y=20;y<s.height;y+=46)c.drawLine(Offset(0,y),Offset(s.width,y-160),p);c.drawCircle(Offset(s.width*.52,s.height*.42),90,Paint()..color=T.mint.withOpacity(.10));c.drawCircle(Offset(s.width*.52,s.height*.42),8,Paint()..color=T.amber);} @override bool shouldRepaint(covariant CustomPainter oldDelegate)=>false;}
